@@ -1,10 +0,0 @@
-style: github
-template: CHANGELOG.tpl.md
-info:
-  title: CHANGELOG
-  repository_url: https://github.com/terraform-aws-modules/terraform-aws-s3-bucket
-options:
-  header:
-    pattern: "^(.*)$"
-    pattern_maps:
-      - Subject
